#include <iostream>
#include <optional>

std::optional<int> lookup(const int* keys, const int* values, int size, int target) {
    for (int i = 0; i < size; ++i)
        if (keys[i] == target) return values[i];
    return std::nullopt;
}

int main() {
    int m;
    std::cin >> m;
    int keys[10], values[10];
    for (int i = 0; i < m; ++i)
        std::cin >> keys[i] >> values[i];
    int target;
    std::cin >> target;

    std::cout << lookup(keys, values, m, target).value_or(0) << '\n';
    return 0;
}
